// Let's verify this with actual values
const e = 1.602176634e-19; // elementary charge in Coulombs
const epsilon0 = 8.8541878128e-12; // vacuum permittivity in F/m
const mu0 = 4 * Math.PI * 1e-7; // magnetic permeability in H/m (exact value)
const hbar = 1.054571817e-34; // reduced Planck constant in J·s
const c = 2.99792458e8; // speed of light in m/s
const pi = Math.PI;

// Original definition
const alpha1 = Math.pow(e, 2) / (4 * pi * epsilon0 * hbar * c);

// Alternative definition using μ₀
const alpha2 = Math.pow(e, 2) * mu0 * c / (4 * pi * hbar);

console.log("Fine structure constant (original definition):", alpha1);
console.log("Fine structure constant (using μ₀):", alpha2);
console.log("Are they equal?", Math.abs(alpha1 - alpha2) < 1e-15);

